def solution():
    # Define variables based on the given problem context
    principal = 200000  # The lump sum invested in the annuity
    interest_rate = 0.0033  # Monthly interest rate as a decimal
    periods = 20 * 12  # Total number of periods (months)

    # Implement the annuity payout calculation
    if interest_rate == 0:
        monthly_payout = principal / periods
    else:
        monthly_payout = principal * (interest_rate * (1 + interest_rate) ** periods) / ((1 + interest_rate) ** periods - 1)

