    return round(monthly_payout)

def solution():
    # Define the specific numerical values given in the problem
    amt_income = 150000
    exemption = 50000
    brackets = {120000: 0.28, 0: 0.26}

    # Calculate the taxable AMTI after exemptions
    taxable_amt_income = max(0, amt_income - exemption)

    # Initialize tentative minimum tax (TMT)
    tmt = 0.0

    # Calculate the TMT using the given brackets
    for threshold, rate in sorted(brackets.items(), reverse=True):
        if taxable_amt_income > threshold:
            tmt += (taxable_amt_income - threshold) * rate
            taxable_amt_income = threshold

    # Return the result rounded to the nearest integer
    return round(tmt)
